mapper.select:
SELECT a.id, a.activity_name as activityName, a.activity_type as activityType, a.cover_image as coverImage, a.description, a.start_time as startTime, a.end_time as endTime, a.max_participants as maxParticipants, a.current_participants as currentParticipants, a.points_reward as pointsReward, a.status, a.create_time as createTime, a.creator_id as creatorId, a.creator_name as creatorName, CASE a.activity_type WHEN 1 THEN '培训讲座' WHEN 2 THEN '知识竞赛' WHEN 3 THEN '演练活动' WHEN 4 THEN '宣传活动' ELSE '其他活动' END as activityTypeName, CASE a.status WHEN 0 THEN '筹备中' WHEN 1 THEN '报名中' WHEN 2 THEN '进行中' WHEN 3 THEN '已结束' WHEN 4 THEN '已取消' ELSE '未知' END as statusName, CASE WHEN ar.id IS NOT NULL THEN 1 ELSE 0 END as isRegistered, CASE WHEN a.max_participants IS NOT NULL AND a.current_participants >= a.max_participants THEN 1 ELSE 0 END as isFull FROM activity a LEFT JOIN activity_registration ar ON a.id = ar.activity_id AND ar.user_id = #{userId} AND ar.deleted = 0 WHERE a.deleted = 0
AND a.status = #{status}
AND a.activity_type = #{activityType}
AND a.activity_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY a.status ASC, a.start_time DESC

mapper.update:
UPDATE activity a
SET current_participants = (
    SELECT COUNT(*) FROM activity_registration 
    WHERE activity_id = #{activityId} AND deleted = 0 AND status != 3
)
WHERE a.id = #{activityId}
